queries.query:
_index=sec_record_* //| limit 100
{{raw_log_keywords}}
metadata_sourceCategory={{raw_log_sourcecategory}}
//| ceil((metadata_parseTime - timestamp) / (1000)) as lag_s_time_to_parse
//| formatdate(_receipttime,"yyyy-MM-dd HH:mm:ss.SSS'Z'","ETC/Utc") as log_received 
//| formatdate(_messagetime,"yyyy-MM-dd HH:mm:ss.SSS'Z'","ETC/Utc") as log_timestamp 
| ceil((_receipttime - _messagetime)  / (1000)) as lag_s_ingest

|values(_view) as indexes,count as records,min(lag_s_ingest) as min_lag_receipt, avg(lag_s_ingest) as avg_lag_receipt,max(lag_s_ingest) as max_lag_receipt by metadata_vendor,metadata_product,metadata_sourceCategory,metadata_mapperName
| "1.OK" as state
| if(max_lag_receipt > {{max_lag_error_secs}},"2.ERR: high lag\nCheck ingest pipeline.", state) as state
| if(min_lag_receipt <0,"3.TZERR: future time\nCheck source TZ config.",state) as state
| sort state,max_lag_receipt

cat {{{lookup}}}
| where time > (now () - (1000 * 60 * 60 * 24 * {{lookback}}))
| tolong(time) as _messagetime
| timeslice by 1w 
| timeToResponse / 3600 as timeToResponse
//| severity as s
//| "OTHER" as severity
//| if (s=1,"1-LOW", severity) as severity
//| if (s=2,"2-MEDIUM", severity) as severity
//| if (s=3,"3-HIGH", severity) as severity
| avg(timeToResponse) as timeToResponse //by _timeslice,severity | transpose row _timeslice column severity

cat {{{lookup}}}
| where time > (now () - (1000 * 60 * 60 * 24 * {{lookback}}))
| tolong(time) as _messagetime
| timeslice by 1w 
| timeToRemediation / 3600 as timeToRemediation
//| severity as s
//| "OTHER" as severity
//| if (s=1,"1-LOW", severity) as severity
//| if (s=2,"2-MEDIUM", severity) as severity
//| if (s=3,"3-HIGH", severity) as severity
| avg(timeToRemediation) as timeToRemediation //by _timeslice,severity | transpose row _timeslice column severity

cat {{{lookup}}}
| where time > (now () - (1000 * 60 * 60 * 24 * {{lookback}}))
| tolong(time) as _messagetime
| timeslice by 1w 
| timeToDetection / 3600 as timeToDetection
//| severity as s
//| "OTHER" as severity
//| if (s=1,"1-LOW", severity) as severity
//| if (s=2,"2-MEDIUM", severity) as severity
//| if (s=3,"3-HIGH", severity) as severity
| avg(timeToDetection) as timeToDetection //by _timeslice,severity | transpose row _timeslice column severity

cat {{{lookup}}}
| where time > (now () - (1000 * 60 * 60 * 24 * {{lookback}}))
| where status="closed"
// severity used to be numeric but now it's not
//| tostring(severity) as sev_string
//| 0 as s
//| if (sev_string matches /1|LOW/,1,s) as s
//| if (sev_string matches /2|MEDIUM/,2,s) as s
//| if (sev_string matches /3|HIGH/,3,s) as s
//| if (sev_string matches /4|CRITICAL/,4,s) as s
//| s as severity
//| if(s = 1,"LOW","OTHER") as severity
//| if(s = 2,"MEDIUM",severity) as severity
//| if(s = 3,"HIGH",severity) as severity
//| if(s = 4,"CRITICAL",severity) as severity
| toint(ceil(timeToDetection / 3600)) as timeToDetection
| toint(ceil(timeToRemediation / 3600)) as timeToRemediation
| toint(ceil(timeToResponse / 3600)) as timeToResponse
| avg(timeToRemediation) as timeToRemediation, avg(timeToResponse) as timeToResponse, avg(timeToDetection) as timeToDetection by assignee
//| timeToResponse-timeToDetection as timeToResponse
| timeToRemediation-timeToResponse as timeToRemediation
//| transpose row severity column timeToDetection,timeToResponse,timeToRemediation

// Use this query to generate a csv you can download then upload to create a lookup table
// use the insightid column as primary key and set a delete TTL to ensure the lookup never exceeds 100 MB (suggested 365d for starters, may need smaller for large accounts)
// Schedule a version of this search to save to the lookup every 15m for -15m 

(_index=sumologic_audit_events _sourcecategory=cseinsight insightupdated
OR
_index=sumologic_system_events _sourcecategory=cseinsight insightcreated)

| json field=_raw "eventName"
| json field=_raw "insightIdentity.id" as id
| json field=_raw "insightIdentity.readableId" as insightid
| json field=_raw "insight.status" as status
| json field=_raw "insight.name" as name
| json field=_raw "insight.entityType" as entitytype
| json field=_raw "insight.entityValue" as entityvalue
| json field=_raw "insight.tags" as tags
| json field=_raw "insight.severity" as severity
| json field=_raw "insight.confidence" as confidence
| json field=_raw "insight.signals" as signals

// in closed events
| json field=_raw "insight.assignee" as assignee nodrop
| json field=_raw "insight.resolution" as resolution nodrop

// in update events 
//| json field=_raw "to" as last_change nodrop

// may exist after an update
| json field=_raw "insight.timeToResponse" as timeToResponse nodrop
| json field=_raw "insight.timeToDetection" as timeToDetection nodrop
| json field=_raw "insight.timeToRemediation" as timeToRemediation nodrop

| if (isnull(timeToResponse),-1,timeToResponse) as timeToResponse
| if (isnull(timeToDetection),-1,timeToDetection) as timeToDetection
| if (isnull(timeToRemediation),-1,timeToRemediation) as timeToRemediation
| sort _messagetime

// ensure we only store the most recent result
| count as events, max(_messagetime) as _messagetime,first(status) as status,first(tags) as tags, max(severity) as severity,first(confidence) as confidence,first(assignee) as assignee,first(resolution) as resolution,first(timeToResponse) as timeToResponse,first(timeToDetection) as timeToDetection,first(timeToRemediation) as timeToRemediation,first(signals) as signals,values(eventname) as eventnames by id,insightid,name,entitytype,entityvalue 

// lets squash down size of the signals field so we don't generate a massive lookup
| parse regex field=signals "\"ruleId\":\"(?<rule>[^\"]+\",\"ruleName\":\"[^\"]+\")" multi
| replace (rule,"\"","") as rule
| replace (rule,"ruleName","") as rule

// final aggregation to save to a lookup with only one row for most recent status of insight
| values(rule) as rules,max(_messagetime) as time,first(status) as status,first(tags) as tags, max(severity) as severity,first(confidence) as confidence,first(assignee) as assignee,first(resolution) as resolution,first(timeToResponse) as timeToResponse,first(timeToDetection) as timeToDetection,first(timeToRemediation) as timeToRemediation,first(eventnames) as eventnames by id,insightid,name,entitytype,entityvalue // first(signals) as signals,

// enable this line to write data to populate the lookup table with backdated data say one time for -90d
// Schedule a version of this search to save to the lookup every 15m for -15m 
//| save path://"/Library/Admin Recommended/CSIEM/Lookups/cse_insights_status"

_index=sec_signal

| if (isempty(suppressedreasons),"NO","YES") as suppressed

| if(suppressed="YES",1,0) as is_suppressed
| if(suppressed="NO",1,0) as is_generated

| json field=entities "[0].value" as entityid nodrop
//
//| json field=fullRecords "[0].metadata_vendor" as vendor nodrop
//| json field=fullRecords "[0].metadata_sourceCategory" as sourceCategory nodrop
//| json field=fullRecords "[0].metadata_product" as product nodrop
//| json field=fullRecords "[0].metadata_mapperName" as mapperName nodrop
//| json field=fullRecords "[0].metadata_deviceEventId" as deviceEventId nodrop
| ruleid as rule_id | rulename as rule_name
//| concat (ruleid," ",rulename) as rule
| if(is_suppressed=1,0,severity) as s
| sum(s) as total_severity,max(severity) as max_sev,count_distinct(entityid) as enitities,sum(is_suppressed) as suppressed,sum(is_generated) as generated by rule_id,rule_name
//| severity * generated as total_severity
| sort total_severity

| tourl(concat("https://{{cse_instance}}/sec/content/rules/rule/",rule_id),rule_id) as rule_id

_index=sec_signal

| if (isempty(suppressedreasons),"NO","YES") as suppressed

| if(suppressed="YES",1,0) as is_suppressed
| if(suppressed="NO",1,0) as is_generated
| json field=entities "[0].type"  as entitytype nodrop
| json field=entities "[0].value" as entityvalue nodrop

//| json field=fullRecords "[0].metadata_vendor" as vendor nodrop
//| json field=fullRecords "[0].metadata_sourceCategory" as sourceCategory nodrop
//| json field=fullRecords "[0].metadata_product" as product nodrop
//| json field=fullRecords "[0].metadata_mapperName" as mapperName nodrop
//| json field=fullRecords "[0].metadata_deviceEventId" as deviceEventId nodrop

| concat (ruleid," ",rulename) as rule
| if(is_suppressed=1,0,severity) as s
| max(severity) as max_sev,sum(s) as total_severity,count_distinct(rule) as rules,sum(is_suppressed) as suppressed,sum(is_generated) as generated by entitytype, entityvalue
//| severity * generated as total_severity
| sort total_severity
|tourl( concat("https://service.us2.sumologic.com/sec/entity?entityId=",entitytype,"-",entityvalue),entityvalue) as entityvalue

