_index=sumologic_system_events "Health-Change" unhealthy
 {{{keywords}}}
//| json "eventType", "resourceIdentity.id" as eventType , resourceId

| json field=_raw "status" 
| json field=_raw "details.error" as error
//| json field=_raw "details.trackerId" as trackerid
//| json field=_raw "resourceIdentity.name" as name
//| concat(name," ",trackerid ) as key 
| 1 as failed
| timeslice by 1h | count by _timeslice,error | transpose row _timeslice column error

cat {{{lookup}}}
| where _timeslice > ( now() - ({{days}} * 1000 * 60 * 60 * 24))
| sum(credits) as credits by uom | sort credits

// metric dpm are problematic for these views as they are the only UOM measured as an average daily rate.
// you could either send a dpm number (but then have to average it instead of sum for every other measure)
// or send datapoints instead in which case you must change the math depending on the time range (as its datapoints / time)
_index=sumologic_volume datapoints
 _sourceCategory = "sourcecategory_metrics_volume"
| parse regex "\"(?<collector>[^\"]+)\"\:\{\"dataPoints\"\:(?<datapoints>\d+)\}" multi
| queryendtime() as _timeslice
| sum(datapoints) as datapoints by _timeslice,collector
| 60 as slice_minutes // this only works correctly for 1 hour slices!
| datapoints / slice_minutes as units
| "metrics" as uom
| "dpm" as unit
// dpms are measured in 24 hour averages
// it's actually a daily average of dpm not hourly
// this is where we have issues here too as the 'rate' for 1 hour is not the same as the 'rate' for 1 day or any other time range
// 24 hours is typically 3 * (dpm / 1000)
| ((1 / ( 24))/1000) * 3 as rate 
| units * rate as credits

// now lets put the 24 hour rate in the rate column as it would be applied to a daily average
// this means the credits column is the credits per hour but the exact dpm could also be
// calculated upstream by avg(units) * rate per 24 hours time range which suits our upstream daily views
/*
for example
rate = 0.003
credits sumo 1 hour = 0.00804
dpm (avg) =   64.3

.00804 * 24 = 19.2  - sum 24 1 hour credits 
64.3 * .003 = 19.2  - if you averaged 24 1 hour units column values and times the daily rate            

*/
| 3 / 1000 as rate

// measure timeslice at end of time unit not start
| tolong(_timeslice + ( 1000 * 60 * 60)) as _timeslice
// fix the double to long bug
| sum(credits) as credits,sum(units) as units by _timeslice,uom,unit,rate
| todouble(rate) as rate
| todouble(credits) as credits
| tolong(_timeslice ) as _timeslice
| todouble(units) as units

// metric dpm are problematic for these views as they are the only UOM measured as an average daily rate.
// you could either send a dpm number (but then have to average it instead of sum for every other measure)
// or send datapoints instead in which case you must change the math depending on the time range (as its datapoints / time)
_index=sumologic_volume datapoints
 _sourceCategory = "sourcecategory_metrics_volume"
| parse regex "\"(?<collector>[^\"]+)\"\:\{\"dataPoints\"\:(?<datapoints>\d+)\}" multi
| timeslice by 1h
| sum(datapoints) as datapoints by _timeslice,collector
| 60 as slice_minutes // this only works correctly for 1 hour slices!
| datapoints / slice_minutes as units
| "metrics" as uom
| "dpm" as unit
// dpms are measured in 24 hour averages
// it's actually a daily average of dpm not hourly
// this is where we have issues here too as the 'rate' for 1 hour is not the same as the 'rate' for 1 day or any other time range
// 24 hours is typically 3 * (dpm / 1000)
| ((1 / ( 24))/1000) * 3 as rate 
| units * rate as credits

// now lets put the 24 hour rate in the rate column as it would be applied to a daily average
// this means the credits column is the credits per hour but the exact dpm could also be
// calculated upstream by avg(units) * rate per 24 hours time range which suits our upstream daily views
/*
for example
rate = 0.003
credits sumo 1 hour = 0.00804
dpm (avg) =   64.3

.00804 * 24 = 19.2  - sum 24 1 hour credits 
64.3 * .003 = 19.2  - if you averaged 24 1 hour units column values and times the daily rate            

*/
| 3 / 1000 as rate

// measure timeslice at end of time unit not start
| tolong(_timeslice + ( 1000 * 60 * 60)) as _timeslice
// fix the double to long bug
| sum(credits) as credits,sum(units) as units by _timeslice,uom,unit,rate
| todouble(rate) as rate
| todouble(credits) as credits
| tolong(_timeslice ) as _timeslice
| todouble(units) as units

| save view credits_usage_hourly_v1

/*
This is an ESTIMATE of storage only.
In order to make the estimate accurate we have to consider:
- retention may vary between customers and partitions
- storage rate are per total GB per day
- billing is on total for current day for all previously ingested GB so over it may take say 30,90 or even 365+ days before storage will peak
- long term growth rate of the account also impacts storage.

we could do a lot of math but it's better just to use fixed numbers based off your account page because storage changes slowly based on long term ingest averages
*/

_index=sumologic_volume _sourcecategory=view_and_tier_volume 
//| parse regex "(?<element>\{[^\}]+})" multi 
//| json field=element "field", "dataTier", "sizeInBytes", "count" as name, uom, bytes, events 
//| limit 1

// take these numbers from your account page
| 1 as daily_storage_gb
| 1 as daily_storage_gb_infrequent
| 0 as daily_storage_gb_security

| concat("storage:", daily_storage_gb,", storage_infrequent:",daily_storage_gb_infrequent,", storage_security:",daily_storage_gb_security) as storage_string
| parse regex field=storage_string "(?<uom>[a-z_]+):(?<units>[0-9]+)" multi
| timeslice by 1h
| "gbytes/day" as unit
| if( uom = "storage",.0067,.0015) as rate
| units / 24 as units
| units * rate as credits // we follow the principle you should be able to sum the 24 hours to = 1 day
//
// measure timeslice at end of time unit not start
| tolong(_timeslice + ( 1000 * 60 * 60)) as _timeslice

//// fix the double to long bug
| max(credits) as credits,max(units) as units by _timeslice,uom,unit,rate
| todouble(rate) as rate
| todouble(credits) as credits
| tolong(_timeslice ) as _timeslice
| todouble(units) as units

// use these to ensure your fixed numbers match account page totals
//| units * 24 as units_day
//| units_day * rate  as cr_day_a
//| credits *24 as cr_day_b

| save view credits_usage_hourly_v1

